function useMarketIndices() {
  const [data, setData] = useState(USE_DUMMY_DATA ? DUMMY_INDICES : []);
  const [loading, setLoading] = useState(!USE_DUMMY_DATA);
  const [error, setError] = useState(null);

  async function fetchData() {
    if (USE_DUMMY_DATA) {
      setData(DUMMY_INDICES);
      setError(null);
      setLoading(false);
      return;
    }
    try {
      setLoading(true);
      const res = await fetch(`${BACKEND_URL}/api/market-indices`);
      if (!res.ok) {
        const errorText = await res.text();
        console.error("Backend API error:", res.status, errorText);
        throw new Error(`Failed to fetch indices: ${res.status} ${res.statusText}`);
      }
      const json = await res.json();
      console.log("Fetched market indices:", json);
      setData(json);
      setError(null);
    } catch (err) {
      console.error("Error fetching market indices:", err);
      setError(err.message || "Unknown error");
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    fetchData();
    // Poll every 15 minutes to reduce API calls and avoid rate limiting (matches backend cache)
    const interval = setInterval(fetchData, 15 * 60_000);
    return () => clearInterval(interval);
  }, []);

  return { data, loading, error, refetch: fetchData };
}

function useGainersLosers() {
  const [data, setData] = useState(USE_DUMMY_DATA ? DUMMY_GAINERS_LOSERS : { gainers: [], losers: [] });
  const [loading, setLoading] = useState(!USE_DUMMY_DATA);
  const [error, setError] = useState(null);

  async function fetchData() {
    if (USE_DUMMY_DATA) {
      setData(DUMMY_GAINERS_LOSERS);
      setError(null);
      setLoading(false);
      return;
    }
    try {
      setLoading(true);
      const res = await fetch(`${BACKEND_URL}/api/gainers-losers`);
      if (!res.ok) {
        const errorText = await res.text();
        console.error("Backend API error:", res.status, errorText);
        throw new Error(`Failed to fetch gainers and losers: ${res.status} ${res.statusText}`);
      }
      const json = await res.json();
      console.log("Fetched gainers and losers:", json);
      setData(json);
      setError(null);
    } catch (err) {
      console.error("Error fetching gainers and losers:", err);
      setError(err.message || "Unknown error");
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    fetchData();
    // Poll every 15 minutes to reduce API calls and avoid rate limiting (matches backend cache)
    const interval = setInterval(fetchData, 15 * 60_000);
    return () => clearInterval(interval);
  }, []);

  return { data, loading, error, refetch: fetchData };
}

function formatNumber(value) {
  if (value == null || Number.isNaN(value)) return "-";
  return value.toLocaleString(undefined, {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  });
}

